// npm install @anthropic-ai/sdk node-fetch
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

async function runTool(name, delayMs) {
  // Simulate an async tool call
  await new Promise((resolve) => setTimeout(resolve, delayMs));
  return { tool: name, result: "ok" };
}

async function agentTurn(userMessage) {
  // 1. Call LLM
  const response = await client.messages.create({
    model: "claude-haiku-4-5",
    max_tokens: 256,
    messages: [{ role: "user", content: userMessage }],
  });

  const text = response.content[0].text;
  console.log("LLM reply:", text);

  // 2. Parallel tool calls via Promise.all
  const toolResults = await Promise.all([
    runTool("search",  400),
    runTool("weather", 300),
    runTool("news",    350),
  ]);

  console.log("Tool results:", toolResults);
  return { reply: text, tools: toolResults };
}

